INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('GADING EDUCATION PARK', '**Pilihan 1 (Fokus pada Inspirasi dan Cahaya)**
Di antara hijaunya Trenggalek, Gading Education Park adalah gerbang menuju cakrawala ilmu. Biarkan jiwa menemukan pijar pengetahuan yang bersinar seindah fajar di taman peradaban ini.

**Pilihan 2 (Fokus pada Ketenteraman dan Pertumbuhan)**
Saksikan perpaduan damai antara alam nan hijau dan gemuruh ide-ide cemerlang. Di sini, setiap langkah adalah pelabuhan, tempat akar ilmu ditanam dan tumbuh subur.

**Pilihan 3 (Fokus pada Perjalanan dan Penemuan)**
Jelajahi semilir angin Tugu, di mana setiap sudut menyimpan kisah belajar tak bertepi. Gading Education Park adalah kanvas jiwa, mengajakmu melukis masa depan penuh makna.', 'Alam', 'Tugu', -8.024018239, 111.5891627, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=GADING%20EDUCATION%20PARK"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('BUKIT TANGGULASI', 'Menyambut lembah dengan gemericik kabut pagi, Bukit Tanggulasi adalah pelukan damai di atas perbukitan hijau Trenggalek. Di sini, biarkan jiwa menemukan ketenangan sambil menikmati spektrum semesta yang terbentang luas di cakrawala.', 'Alam', 'Tugu', -8.024183072731027, 111.60243467673402, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=BUKIT%20TANGGULASI"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('TAMAN TUMPUK', '**Pilihan 1: (Menekankan kedalaman dan lapisan waktu)**
Di sini, setiap sudut adalah susunan kisah alam yang menenangkan; tumpukan hijau yang mengajak jiwa melangkah perlahan menapaki keindahan abadi. Merangkai damai dalam tiap lapis daun, Taman Tumpuk adalah oase di mana waktu terasa berhenti dan memelukmu.

**Pilihan 2: (Menekankan visual dan keindahan yang menumpuk)**
Menyambut hijaunya alam yang bertumpuk dalam palet damai, Taman Tumpuk adalah labirin visual penuh kejutan. Biarkan matamu berkelana di antara lapisan-lapisan hijau, menemukan simfoni teduh di jantung Trenggalek.

**Pilihan 3: (Lebih puitis, fokus pada perasaan)**
Temukan kedamaian yang tersusun, di mana hijaunya pepohonan menumpuk menjadi kanvas pelukan alam. Biarkan jiwa berbisik bersama gemericik sunyi di Tugu, menikmati setiap tarikan napas yang menenangkan.', 'Alam', 'Tugu', -8.054983274735338, 111.64702980443975, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=TAMAN%20TUMPUK"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('WISATA BENDUNGAN TUGU', '**Pilihan 1 (Fokus pada Keagungan dan Refleksi)**
Di sini, air menari membelah waktu, menciptakan cermin raksasa yang memantulkan langit dan semesta Trenggalek. Rasakan ketenangan abadi di antara gemuruh air dan bisik alam yang tak pernah berhenti bercerita.

**Pilihan 2 (Fokus pada Ketenangan dan Pesona)**
Sebuah mahakarya alam dan rekayasa yang menawarkan jeda damai dari hiruk pikuk hari. Biarkan mata dan jiwa berlayar di bawah teduh pantulan air bendungan, menemukan kedamaian sejati di Tugu.

**Pilihan 3 (Lebih Puitis dan Metaforis)**
Tempat pertemuan di mana batu membisu menyaksikan sungai merangkai melodi abadi. Bendungan ini bukan hanya penahan air, melainkan kanvas jiwa yang merefleksikan kedamaian di jantung Trenggalek.', 'Alam', 'Tugu', -8.036845284215296, 111.58480480258179, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=WISATA%20BENDUNGAN%20TUGU"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('WISATA EMBUNG SLOBOG', 'Berikut adalah beberapa pilihan deskripsi yang menarik dan puitis, tergantung *vibe* yang ingin ditonjolkan:

**Pilihan 1: Fokus pada Ketenangan dan Refleksi (Paling Direkomendasikan)**
Di Embung Slobog, temukan pelukan damai alam yang memantulkan langit dan semesta. Biarkan setiap bisikan air menjadi jeda bagi jiwa yang lelah, tempat merangkai kembali damai hati.

**Pilihan 2: Fokus pada Keindahan Visual dan Magis**
Kehangatan Trenggalek bertemu dengan ketenangan perairan Slobog, menciptakan lukisan alami yang memukau. Di sinilah, setiap sudut air adalah cermin rahasia, merekam keindahan semesta dalam balutan senja.

**Pilihan 3: Fokus pada Kedamaian dan Pelarian (Lebih puitis)**
Biarkan langkah membawa jiwa ini menemukan jeda di Embung Slobog. Airnya adalah pentas refleksi, tempat raga dan pikiran beristirahat dalam pelukan ketenangan Tugu.', 'Alam', 'Tugu', -8.073232086903479, 111.62407068089239, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=WISATA%20EMBUNG%20SLOBOG"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('WAHANA WISATA BANYU LUMUT (WBL)', 'Temukan ketenangan di tepi air yang memeluk rimbunnya lumut hijau, di mana setiap alirannya membisikkan kedamaian alam. WBL adalah oase pelarian di jantung Trenggalek, tempat jiwa raga berdamai bersama pesona sejuk Tugu.', 'Alam', 'Tugu', -8.01138133837308, 111.64358681267176, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=WAHANA%20WISATA%20BANYU%20LUMUT%20(WBL)"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Pantai Tirisan', '**Pilihan 1 (Nuansa Romantis & Tenang):**
Di hamparan pasir emas Pantai Tirisan, ombak berbisik melodi abadi yang memeluk jiwa. Rasakan kedamaian di perbatasan langit dan samudra, sebuah pelukan hangat dari Panggul.

**Pilihan 2 (Nuansa Puitis & Megah):**
Di ufuk barat Trenggalek, tempat semesta bertemu lekuk ombak dalam tarian senja. Biarkan jiwamu berdamai dalam keagungan Pantai Tirisan, sebuah janji kedamaian di tepi samudra.

**Pilihan 3 (Nuansa Sederhana & Magis):**
Pantai Tirisan adalah bisikan rahasia antara daratan dan lautan. Keindahan Panggul yang membius mata, di mana waktu seakan berhenti di antara debur ombak dan langit senja.', 'Pantai', 'Panggul', -8.27471, 111.4064251, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Pantai%20Tirisan"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Pantai Watu Pawon', 'Di tepian Panggul, biarkan gemuruh ombak berbisik menenangkan jiwa di antara lekuk batu-batu misterius. Saksikan senja membakar langit, mewarnai pasir putih menjadi kanvas keindahan yang tak lekang oleh waktu.', 'Pantai', 'Panggul', -8.2986452, 111.4478404, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Pantai%20Watu%20Pawon"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Pantai Kuyon', '**Pilihan 1 (Fokus pada Ketenangan dan Keindahan Senja):**
Biarkan Pantai Kuyon melukiskan kisah senja di batas cakrawala. Di sini, pasir dan samudra berbisik, memanggil jiwa yang mencari kedamaian abadi.

**Pilihan 2 (Fokus pada Sensori dan Keajaiban Alam):**
Saksikan pertemuan gemuruh ombak dengan lembutnya pasir, seolah alam sedang membisikkan mantra kedamaian. Biarkan semilir angin Panggul memelukmu, membawa serta melodi samudra yang tak pernah usai.

**Pilihan 3 (Paling Singkat dan Puitis):**
Di ujung kaki Trenggalek, Pantai Kuyon adalah pelukan abadi antara debur ombak dan hamparan emas. Sebuah oase di mana jiwa menemukan jeda, dan waktu terasa berhenti.', 'Pantai', 'Panggul', -8.2963211, 111.4470593, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Pantai%20Kuyon"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Pantai Joketro', '**Pilihan 1 (Fokus: Kedamaian dan Senja)**
Di Pantai Joketro, setiap bisikan ombak adalah melodi syahdu yang menenangkan jiwa. Biarkan senja memeluk cakrawala, dan saksikan hamparan pasirnya menjadi saksi pertemuan antara langit dan samudra yang abadi.

**Pilihan 2 (Fokus: Keindahan Alam dan Aura)**
Jelajahi pesona Jogetro, di mana biru samudra seolah membisikkan rahasia waktu yang terlupakan. Berjalanlah di tepian pasirnya, dan biarkan keindahan murni Panggul ini menyentuh relung hatimu.

**Pilihan 3 (Fokus: Metafor dan Kesan Romantis)**
Sebuah pelabuhan bagi jiwa yang lelah, di mana pasir keemasan bertemu birunya janji ombak. Di sini, waktu berhenti; hanya ada kita, langit, dan pesona Pantai Joketro yang memukau.', 'Pantai', 'Panggul', -8.2874929, 111.4521505, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Pantai%20Joketro"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Pantai Taman Kili-Kili', 'Di ujung Panggul, Pantai Taman Kili-Kili memeluk pasir keemasan yang dibisikkan ombak, menyajikan panorama matahari terbenam di antara bukit-bukit hijau nan megah. Keindahan magis ini adalah pelukan hangat Samudra Hindia, tempat waktu seolah berhenti dan jiwa menemukan ketenangan.', 'Pantai', 'Panggul', -8.2596, 111.4304, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Pantai%20Taman%20Kili-Kili"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Pantai Konang', '**Pilihan 1 (Nuansa Tenang dan Romantis):**
Di sini, ombak berbisik pelan memecah birunya cakrawala, membawakan semilir damai yang membelai jiwa. Pantai Konang adalah lukisan senja abadi, tempat pasir bertemu janji matahari terbenam yang sempurna.

**Pilihan 2 (Nuansa Megah dan Puitis):**
Biarkan pasir emas menjadi saksi setiap jejak kaki, sementara deburan ombak menjadi irama purba yang menenangkan raga. Menatap Konang, kamu akan menemukan perpaduan magis antara langit, laut, dan semesta yang tak bertepi.

**Pilihan 3 (Nuansa Misterius dan Eksotis):**
Hamparan Konang menanti dengan keindahan yang membuai, di mana langit bertemu laut dalam sapuan warna jingga keemasan. Rasakan bisikan angin laut yang membawa kisah-kisah tak terucap dari ujung pulau.', 'Pantai', 'Panggul', -8.2748, 111.4529, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Pantai%20Konang"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Pantai Pelang', 'Di ufuk Panggul, Pantai Pelang merebahkan senja dengan palet warna yang memukau, di mana pasir keemasan bertemu bisikan ombak Samudra yang menenangkan. Biarkan jiwa Anda tersapu gemerlap pesisir ini, menemukan bait-bait puisi dalam setiap debur napas samudra.', 'Pantai', 'Panggul', -8.2578, 111.4239, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Pantai%20Pelang"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('EMBUNG WAKELAN', '**Pilihan 1 (Fokus pada Ketenangan dan Pantulan):**
Biarkan jiwa mereda dalam pelukan sunyi Embung Wakelan, di mana air menjadi cermin rahasia semesta. Di tepian Dongko ini, setiap riak adalah bisikan damai antara langit dan bumi.

**Pilihan 2 (Fokus pada Suasana Puitis dan Keindahan):**
Menemukan ketenangan hakiki di pelukan Embung Wakelan, tempat waktu seolah melambat dan membeku. Datanglah dan saksikan keindahan magis di mana langit dan air menari dalam keheningan Trenggalek.', 'Alam', 'Dongko', -8.184801959451319, 111.57531510071337, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=EMBUNG%20WAKELAN"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('JURUG MANGU', '**Pilihan 1 (Fokus pada Keheningan dan Jiwa):**
Di pelukan hijau Dongko, Juru Mangu menawarkan bisikan kedamaian yang lama dicari. Biarkan jiwa menemukan ritme sunyi, ditemani keajaiban alam yang menenangkan hati.

**Pilihan 2 (Fokus pada Misteri dan Keindahan):**
Jelajahi pesona mistis di Juru Mangu, tempat semesta menyusun kisah di setiap jengkal lembah. Sebuah oase tersembunyi di Trenggalek, di mana alam dan waktu seolah berhenti berdetak.

**Pilihan 3 (Paling Puitis dan Metaforis):**
Di antara hijaunya perbukitan Dongko, terlukis kanvas ketenangan bernama Juru Mangu. Datanglah dan biarkan gemuruh alam menyanyikan melodi yang menyejukkan setiap lekuk penat di jiwa.', 'Alam', 'Dongko', -8.192454585542606, 111.55572962214141, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=JURUG%20MANGU"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('HUTAN GUNUNG SEMUNGKLUNG', 'Di pelukan semesta hijau, Semungklung adalah simfoni pepohonan yang merajut misteri di antara kabut pagi. Biarkan hati menelusur jejak damai, menemukan ketenangan abadi di jantung gunung Trenggalek.', 'Hutan', 'Dongko', -8.14657128329453, 111.56470146391936, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=HUTAN%20GUNUNG%20SEMUNGKLUNG"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Air Terjun Jurug Waru', '**Opsi 1 (Fokus pada Keindahan dan Kedamaian):**
Gemericikan air yang jatuh membelah rimbunnya hijau, membawa bisikan kedamaian dari jantung Trenggalek. Di sini, waktu seolah berhenti dalam pelukan semilir sejuk dan kabut air yang mempesona.

**Opsi 2 (Fokus pada Suara dan Rasa Magis):**
Dengarkanlah melodi alam yang agung, di mana tirai air menari memecah kesunyian hutan. Jurug Waru menawarkan pelukan sejuk, menyegarkan jiwa yang haus akan keindahan purba.

**Opsi 3 (Paling Singkat dan Puitis):**
Di bawah naungan hijau hutan Dongko, air bersemilir menaburkan pesona yang membius. Sebuah oase sejati, tempat jiwa menemukan ketenangan di bawah gemuruh air yang abadi.', 'Alam', 'Dongko', -8.245979487220419, 111.51796146447056, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Air%20Terjun%20Jurug%20Waru"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Air Terjun Kali Jodo', '**Opsi 1 (Fokus pada ketenangan dan keindahan alam):**
Di kedalaman rimbunnya hutan Trenggalek, terhampar oase magis tempat air berbisik lembut. Saksikan kemegahan tirai air yang jatuh, memeluk kedamaian yang hanya ditemukan di pangkuan alam.

**Opsi 2 (Fokus pada suara dan energi penyembuhan):**
Dengarkan simfoni derasnya air yang memecah keheningan dongko, membawa energi segar bagi jiwa. Air Terjun Kali Jodo adalah pelarian puitis, di mana setiap tetesnya membersihkan penat dan menyegarkan raga.

**Opsi 3 (Paling singkat dan puitis):**
Temukan permata tersembunyi yang berbisik di antara rimbunnya hutan Jawa. Keagungan Air Terjun Kali Jodo mengajakmu merangkul ketenangan yang memancar dari gemericiknya.', 'Alam', 'Dongko', -8.160309186805097, 111.61773900679678, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Air%20Terjun%20Kali%20Jodo"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('REST AREA THUK DALI', 'Temukan jeda damai di tengah pesona hijau Trenggalek; tempat di mana keheningan alam memeluk setiap langkah perhentian. Biarkan jiwa berbisik bersama angin, menikmati lukisan senja yang tak pernah membosankan di sudut Thuk Dali.', 'Alam', 'Dongko', -8.143948275960105, 111.58200614912442, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=REST%20AREA%20THUK%20DALI"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('REST AREA KALI GESING', 'Di sini, semilir angin menyambut jiwa dengan pelukan alam yang menyejukkan, sembari sungai kali gesing mengalirkan melodi ketenangan di sudut Dongko yang membumi. Nikmati jeda semesta dalam rona hijau pegunungan dan semilir napas kehidupan, menjadikannya pelabuhan jiwa di tengah perjalananmu.', 'Alam', 'Dongko', -8.207109312698478, 111.55455387981371, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=REST%20AREA%20KALI%20GESING"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('BUKIT BRAKSINTO', '**Pilihan 1: (Fokus pada Misteri & Kabut)**
Di puncak Bukit Braksinto, kabut pagi akan menari-nari menyambut jiwa yang damai. Rasakan bisikan alam Trenggalek yang megah, menyuguhkan hamparan hijau keabadian yang menenangkan setiap langkah kaki.

**Pilihan 2: (Fokus pada Keagungan & Kedamaian)**
Temukan kedamaian hakiki di punggung bukit yang memeluk langit Dongko. Bukit Braksinto adalah kanvas alam tempat hijaunya pepohonan berdialog dengan semilir angin, meninggalkan jejak kenangan yang syahdu.

**Pilihan 3: (Singkat, Puitis, dan Eksotis)**
Biarkan matamu terbius oleh panorama hijau Bukit Braksinto; tempat di mana awan berpadu dengan lembah. Sebuah pelukan alam yang magis, menunggu untuk kamu temukan keindahannya.', 'Alam', 'Dongko', -8.243410141328805, 111.58122422977512, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=BUKIT%20BRAKSINTO"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Desa Wisata Pandean River Tubing Watu Kandang', 'Biarkan sungai menjadi kanvas petualanganmu, menyingkapkan keindahan alam dan misteri gemericik air di Pandean. Di sinilah ketenangan bertemu hiruk pikuk petualangan, di antara lekukan sungai dan megahnya Watu Kandang di jantung Trenggalek.', 'Alam', 'Dongko', -8.238433025819345, 111.53570860893848, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Desa%20Wisata%20Pandean%20River%20Tubing%20Watu%20Kandang"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('PENDAKIAN SANGYANG WILIS VIA BOTOPUTIH', '**Opsi 1: (Fokus pada Keindahan dan Proses)**
Tinggalkan jejak kakimu menyusuri hijaunya bukit, menapaki kisah peradaban di setiap tikungan Botoputih. Di puncak ini, semesta akan menyambutmu dengan hamparan kabut, mengajarkan arti tenang sejati dari sebuah pendakian.

**Opsi 2: (Fokus pada Spirit dan Misteri)**
Biarkan kaki meniti langkah menuju Sanyang Wilis, tempat di mana hutan bertemu langit dalam pelukan misteri. Di Bendungan, Trenggalek, kau tak hanya mendaki gunung, namun juga menemukan jeda damai bagi jiwa yang penat.

**Opsi 3: (Paling Puitis dan Singkat)**
Menyambut panorama alam purba dari ketinggian, di mana hijau pepohonan berbisik dengan lagu angin yang menderu. Pendakian ini adalah janji pertemuan antara kaki petualang dan semesta yang tak bertepi.', 'Alam', 'Bendungan', 0, 0, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=PENDAKIAN%20SANGYANG%20WILIS%20VIA%20BOTOPUTIH"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('TAMAN MASKUMAMBANG', 'Di pelukan air bendungan, Maskumambang adalah hamparan hijau yang memeluk ketenangan jiwa. Sempurnakan momenmu dengan bisikan angin dan panorama alam yang seolah menghentikan waktu di jantung Trenggalek.', 'Alam', 'Bendungan', 0, 0, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=TAMAN%20MASKUMAMBANG"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('COBAN RAMBAT', '**Pilihan 1: (Fokus pada ketenangan dan magis)**
Coban Rambat menyuguhkan simfoni alam yang tak pernah usai; riak air yang menari di antara bebatuan hijau membisikkan ketenangan jiwa. Di sini, setiap gemericikannya adalah pelukan sejuk yang membawa raga kembali pada detak damai semesta.

**Pilihan 2: (Fokus pada kemegahan dan energi alam)**
Saksikanlah gemuruh Coban Rambat, menyaksikan kekuatan alam yang melukiskan keindahan abadi di jantung Trenggalek. Tempat ini adalah nafas sejuk yang memulihkan, menyatukan jiwa yang lelah dengan irama semesta.

**Pilihan 3: (Lebih puitis dan sensual)**
Jelajahi Coban Rambat, di mana tirai air jatuh memecah keheningan menjadi melodi membius. Rasakan setiap tetesnya menyentuh kulit, membisikkan rahasia magis yang hanya milik alam.', 'Alam', 'Bendungan', 0, 0, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=COBAN%20RAMBAT"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('TELOGO KEBAK', '**Pilihan 1 (Paling Puitis & Liris):**
Di sini, langit dan air menari dalam keheningan yang syahdu. Telogo Kebak adalah pelabuhan bagi jiwa, tempat damai berbisik di setiap lekuk pantulan semesta.

**Pilihan 2 (Menekankan Ketenangan & Kedamaian):**
Biarkan hiruk pikuk hari menepi, dan temukan ketenangan abadi di pelukan alam ini. Telogo Kebak, cerminan hati yang menemukan jeda paling indah.

**Pilihan 3 (Metaphoris & Megah):**
Sebuah mahakarya alam di tepi bendungan Trenggalek. Saksikan bagaimana Telogo Kebak merangkai permadani warna, memantulkan keagungan langit dalam damai yang tak bertepi.', 'Alam', 'Bendungan', 0, 0, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=TELOGO%20KEBAK"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('GUA BIRU', 'Tersembunyi di jantung Trenggalek, Gua Biru adalah bisikan warna langit yang memeluk bumi. Masuki kedalamannya, dan biarkan jiwamu hanyut dalam keajaiban biru kristal yang seolah membekukan kedamaian semesta.', 'Alam', 'Bendungan', 0, 0, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=GUA%20BIRU"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('TAMAN JALU MAMPANG', 'Di tepian Bendungan yang membiru, Taman Jalu Mampang menawarkan panorama magis antara hijau pepohonan dan pantulan langit. Datanglah ke sini, temukan pelabuhan damai tempat jiwa berbisik damai, membuai raga dalam ketenangan alam Trenggalek.', 'Alam', 'Bendungan', 0, 0, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=TAMAN%20JALU%20MAMPANG"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('PUTRI MARON', '**Pilihan 1: Fokus pada Keindahan Visual dan Kedamaian (Paling puitis)**
Di pelukan air bendungan yang tenang, Putri Maron adalah kanvas alam tempat langit berbisik dan senja merangkai warna. Biarkan diri hanyut dalam keajaiban refleksi air, sebuah pelarian yang menghipnotis jiwa.

**Pilihan 2: Fokus pada Magis dan Atmosfer (Lebih misterius)**
Menyambut gemericik air dan bisikan angin, Putri Maron adalah gerbang ke ketenangan yang tersembunyi di jantung Trenggalek. Di sini, setiap sudut menyimpan pesona waktu yang melambat, seolah dunia hanya untuk kita.

**Pilihan 3: Fokus pada Warna dan Kontras (Elegan dan menggugah)**
Putri Maron menyajikan simfoni warna antara biru air yang jernih dan nuansa kemerahan senja yang memeluk. Nikmati keagungan bentangan alam yang tak hanya dilihat, namun juga dirasakan hangatnya di jiwa.', 'Alam', 'Bendungan', 0, 0, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=PUTRI%20MARON"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('DILLEM WILIS', 'Di pelukan Bendungan, Dillem Wilis adalah kanvas alam tempat langit berbisik pada air, menciptakan refleksi tak bertepi. Datanglah, dan temukan jeda waktu di antara gemericik ombak yang membiarkan hati tak lagi tahu harus memilih jalan yang mana.', 'Alam', 'Bendungan', 0, 0, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=DILLEM%20WILIS"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Kahyangan View Bukit Abimanyu', '**Pilihan 1 (Elegan dan Megah)**
Dari bukit ini, cakrawala terhampar bagai permadani surga yang memukau mata. Rasakan kedamaian sejati dan eloknya pemandangan kahyangan di setiap helai angin Bukit Abimanyu.

**Pilihan 2 (Puitis dan Romantis)**
Di pelukan hijau Bukit Abimanyu, semilir angin membisikkan bisikan damai. Saksikan kanvas langit yang dilukis semesta, seolah kaki melangkah ke kahyangan di jantung Trenggalek.

**Pilihan 3 (Singkat dan Mengajak)**
Menanti detik di puncak yang seolah tiada batasnya, di mana langit bertemu dengan kabut keabadian. Kahyangan View ini adalah pelabuhan jiwa untuk jiwa yang mencari ketenangan sejati.', 'Alam', 'Suruh', -8.098403333147633, 111.59393611049742, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Kahyangan%20View%20Bukit%20Abimanyu"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Wisata Bolu Rindu Tanggulasi', '**Opsi 1 (Fokus Nostalgia & Romantisme):**
Di tepi Tanggulasi, rindu berbisik lembut bersama semilir angin Trenggalek. Tempat ini adalah pelukan hangat bagi jiwa yang merindukan ketenangan dalam balutan keindahan alam.

**Opsi 2 (Fokus Kelembutan & Kenyamanan - Menggunakan metafora ''Bolu''):**
Senja di sini selembut bolu, menebar rindu dalam setiap sudut alam. Biarkan hati menemukan jeda yang manis, ditemani keindahan hijau yang menenangkan jiwa.

**Opsi 3 (Fokus Kedamaian & Keajaiban Alam):**
Sebuah oase di jantung Trenggalek, di mana waktu seolah tertahan dalam senyum Tanggulasi. Berhenti sejenak, dan temukan keajaiban rindu yang tak pernah usai di pelukan alam.', 'Alam', 'Suruh', -8.098209484371631, 111.60544278719495, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Wisata%20Bolu%20Rindu%20Tanggulasi"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Air Terjun Jurug Gue', '**Opsi 1 (Nuansa Magis dan Damai):**
Biarkan gemericik air yang jatuh menenangkan jiwa, menyeruput keindahan seolah tirai perak yang membelah rimbunnya hutan hijau. Di sinilah Jurug Gue, oase rahasia Trenggalek tempat waktu seolah berhenti.

**Opsi 2 (Nuansa Puitis dan Pengalaman):**
Dengarkan bisikan air yang menyapa dari kedalaman alam, menciptakan sapuan kabut perak di antara pepohonan purba. Menemukan ketenangan abadi di Air Terjun Jurug Gue, tempat jiwa dan raga berdamai.

**Opsi 3 (Nuansa Deskriptif dan Menyegarkan):**
Saksikan keagungan jatuhnya air yang memantulkan warna hijau zamrud, memecah keheningan dalam semburan energi alami. Surga tersembunyi di Suruh ini menunggu Anda, membasuh penat dengan sejuknya neci hutan.', 'Alam', 'Suruh', -8.127252448098199, 111.6383807498454, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Air%20Terjun%20Jurug%20Gue"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Wisata Tebing Lingga', '**Pilihan 1 (Nuansa Megah dan Kontemplatif):**
Di batas cakrawala, Tebing Lingga berdiri memamerkan kemegahan ciptaan yang sunyi. Tempatkan jiwamu sejenak di sini, dan biarkan angin membawa setiap penatmu menghilang bersama senja.

**Pilihan 2 (Nuansa Puitis dan Menenangkan):**
Rasakan sapuan angin purba yang membelai tebing-tebing penuh misteri ini. Tebing Lingga adalah jeda waktu yang abadi, menawarkan kanvas senja paling indah di jantung Trenggalek.

**Pilihan 3 (Nuansa Dramatis dan Mengundang):**
Saksikan bentangan tebing yang berbisik tentang kekuatan alam, saksi bisu setiap detik matahari terbit dan terbenam. Kedatanganmu di sini adalah pelukan keajaiban yang menunggu di tepian waktu.', 'Alam', 'Suruh', -8.109596585852394, 111.59951682581588, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Wisata%20Tebing%20Lingga"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Pantai Prigi 360', '**Pilihan 1 (Fokus pada Panorama dan Magis Senja):**
Biarkan ombak Watulimo membisikkan kisah di hamparan pasir keemasan. Di Pantai Prigi 360, setiap sudut adalah panggung magis di mana senja tak pernah usai.

**Pilihan 2 (Fokus pada Keindahan Alam dan Kedamaian):**
Di sini, cakrawala membentang dalam pelukan biru tanpa batas, menenangkan jiwa yang penat. Nikmati harmoni abadi antara debur ombak dan hangatnya pasir di 360 derajat keindahan.

**Pilihan 3 (Lebih Puitis dan Metaforis):**
Saksikan perpaduan warna langit dan laut yang menari di Pantai Prigi 360. Tempat di mana waktu seolah berhenti, membiarkan jiwa berdamai dalam irama ombak yang tak pernah lelah.', 'Pantai', 'Watulimo', -8.28574, 111.72578, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Pantai%20Prigi%20360"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Camp Sengunglung', 'Terperangkap dalam pelukan hijau Pule, Camp Sengunglung adalah tempat di mana waktu berbisik pelan, membawa jiwa pada heningnya alam yang sejati. Di sini, biarkan bintang dan semilir angin membimbingmu kembali pada ketenangan yang telah lama hilang.', 'Alam', 'Pule', -8.14, 111.57, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Camp%20Sengunglung"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Sawah Gede', '**Pilihan 1 (Elemen Visual & Keindahan Senja):**
Hamparan hijau Sawah Gede adalah kanvas agung yang dilukis oleh alam, di mana setiap petak sawah berbisik dengan ketenangan. Saksikan simfoni warna saat mentari senja menyelimuti lembah Pule, menciptakan pemandangan tak tertandingi.

**Pilihan 2 (Elemen Ketenangan & Jiwa):**
Di sini, waktu merayap pelan mengikuti irama air dan angin sawah yang menyejukkan jiwa. Biarkan Sawah Gede menjadi pelukan damai, tempat hati menemukan kembali ketenangan di tengah hijaunya Trenggalek.

**Pilihan 3 (Elemen Kontras & Megah):**
Inilah hamparan emas hijau yang tak bertepi, seolah menyentuh batas langit Pule. Sawah Gede menawarkan kemegahan alam yang abadi, mengajak mata untuk larut dalam keajaiban kehidupan pedesaan.', 'Alam', 'Pule', -8.13, 111.55, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Sawah%20Gede"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Taman Karang Sinawung', 'Berikut adalah tiga pilihan deskripsi, tergantung pada nuansa (mistis, tenang, atau megah) yang diinginkan:

***

**Pilihan 1 (Nuansa Magis & Romantis):**
Di hamparan karang Sinawung, waktu seolah membeku dalam bisikan ombak yang syahdu. Biarkan jiwamu menari mengikuti melodi biru yang menenangkan di lekuk Trenggalek.

**Pilihan 2 (Nuansa Tenang & Damai):**
Saksikan perpaduan warna dan keajaiban alam yang terukir di setiap karang Pule. Di sini, setiap hembusan angin adalah bisikan damai yang merajut kembali ketenangan jiwa.

**Pilihan 3 (Nuansa Emas & Megah):**
Inilah pelukan karang yang menyimpan permata biru di tepi Trenggalek. Sebuah mahakarya alam yang mengajak langkahmu menyeberang menuju kedamaian abadi.', 'Alam', 'Pule', -8.09, 111.56, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Taman%20Karang%20Sinawung"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Air Terjun Songgo Langit', '**Pilihan 1 (Fokus pada Suara dan Keajaiban):**
Di antara rimbunnya hijau Trenggalek, dengarkan bisikan gemericik air yang seolah menari melodi dari langit. Songgo Langit adalah pelukan magis alam, tempat jiwa menemukan kedamaian di bawah tirai air yang abadi.

**Pilihan 2 (Fokus pada Visual dan Ketenangan):**
Saksikanlah keagungan air yang jatuh menembus kabut pagi, seolah menyambutmu dari singgasana langit. Di sini, setiap tetes air merangkai kisah ketenangan, memelukmu dalam dekapan alam yang tak tersentuh.

**Pilihan 3 (Paling Puitis dan Singkat):**
Tempat di mana air berbisikkan mantra keindahan, menuruni palung panca warna yang magis. Songgo Langit adalah oasis jiwa, di mana kabut dan melodi alam berpadu menjadi simfoni semesta.', 'Alam', 'Pule', -8.06, 111.59, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Air%20Terjun%20Songgo%20Langit"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Argo Lawe', '**Pilihan 1 (Fokus pada Kedamaian dan Pelarian)**
Di pelukan hijaunya Trenggalek, Argo Lawe adalah jeda abadi bagi jiwa yang lelah. Biarkan semilir angin membawa damai, dan biarkan sungai membisikkan kisah kedamaian yang sejati.

**Pilihan 2 (Fokus pada Keindahan Magis dan Alam)**
Saksikanlah keagungan arsitektur alam di Argo Lawe, tempat kabut pagi menari di atas lembah hijau. Sebuah oase rahasia yang menjanjikan pelukan semesta dan kedamaian di setiap sudut pandang.

**Pilihan 3 (Lebih Puitis dan Romantis)**
Di lembah Pule yang syahdu, Argo Lawe memanggil para pencari senja. Keindahan yang membisikkan melodi alam, tempat jiwa bertemu kanvas hijau semesta.', 'Alam', 'Pule', -8.08, 111.54, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Argo%20Lawe"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Kolam Renang Taman Surya', '**Pilihan 1 (Fokus: Keteduhan dan Harmoni)**
Biarkan dirimu hanyut dalam biru jernih Taman Surya, di mana riak air merangkul kehangatan mentari. Ini adalah oase teduh di Pule, Trenggalek, tempat jiwa menemukan jeda yang damai.

**Pilihan 2 (Fokus: Visual dan Magis)**
Sebuah lukisan biru yang hidup, memantulkan setiap emasnya bias mentari Pule. Nikmati senja di Kolam Renang Taman Surya, pelarian magis dari hiruk pikuk dunia.

**Pilihan 3 (Fokus: Perasaan dan Kenyamanan)**
Di sini, setiap cipratan air adalah melodi yang memeluk kehangatan semesta. Sambut kedamaian di Taman Surya, tempat kolam membisikkan kisah istirahat di jantung Trenggalek.', 'Alam', 'Pule', -8.13, 111.56, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Kolam%20Renang%20Taman%20Surya"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Makam Kanjeng Jimat - Margoayu', '**Pilihan 1: Fokus pada Nuansa Spiritual dan Kedamaian**
Di hamparan Makam Kanjeng Jimat, waktu seakan berhenti dalam hening yang sakral. Rasakan damai jiwa dan dengarkan bisikan kisah-kisah para leluhur yang bersemayam abadi di jantung Trenggalek.

**Pilihan 2: Fokus pada Misteri dan Keagungan Sejarah**
Inilah titik temu antara sejarah dan spiritualitas; tempat di mana setiap batu nisan menorehkan kisah tak lekang dimakan zaman. Datanglah menelusuri jejak kebijaksanaan makam ini, merasakan aura magis yang menyelimuti bukit Pogalan.

**Pilihan 3: Singkat, Puitis, dan Evokatif**
Melangkah ke relung Makam Jimat, menapaki sunyi yang menyimpan seribu bisikan sejarah. Keheningan di sini bukan ketiadaan suara, melainkan lantunan damai dari masa lampau yang abadi.', 'Goa', 'Pogalan', -8.2144, 111.1158, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Makam%20Kanjeng%20Jimat%20-%20Margoayu"]', 0, 4.0);
INSERT OR REPLACE INTO wisata (nama, deskripsi, kategori, kecamatan, latitude, longitude, foto, highlight, rating) VALUES 
('Candi Brongkah', 'Berikut adalah beberapa pilihan, tergantung nuansa puitis apa yang ingin Anda tonjolkan (Misteri, Kedamaian, atau Keagungan Sejarah).

***

**Pilihan 1: Nuansa Misterius dan Waktu**
Di antara gemerisik dedaunan Pogalan, Candi Brongkah berbisikkan rahasia masa silam. Jelajahi keheningan abadi, di mana waktu seakan berhenti dan menyapa jiwa.

**Pilihan 2: Nuansa Spiritual dan Kedamaian**
Biarkan diri terhanyut dalam sapuan sunyi di relung candi purba ini. Sebuah oase sakral di Trenggalek, tempat jiwa mencari damai di pelukan keagungan batu.

**Pilihan 3: Nuansa Puitis dan Kontras (Alam vs. Sejarah)**
Ketika senja memeluk reruntuhan candi, kisah peradaban agung menjadi bisikan angin. Di sinilah, keindahan alam dan keheningan sejarah berpadu dalam bingkai magis.', 'Alam', 'Pogalan', -8077, 111.706, '["https://images.unsplash.com/photo-1501785888041-af3ef285b470?q=80&w=1000&auto=format&fit=crop&sig=Candi%20Brongkah"]', 0, 4.0);
